# Read reviews from 2020 onwards from the file
reviews_file = var_functions.query_db_63
with open(reviews_file, 'r') as f:
    reviews_2020 = json.load(f)

# Filter and aggregate ratings for children's books
from collections import defaultdict

book_ratings = defaultdict(list)
for review in reviews_2020:
    purchase_id = review['purchase_id']
    if purchase_id in children_books:
        try:
            rating = float(review['rating'])
            book_ratings[purchase_id].append(rating)
        except (ValueError, TypeError):
            continue

# Calculate average ratings and find highly rated books
highly_rated_books = []
for purchase_id, ratings in book_ratings.items():
    if ratings:  # Ensure there are ratings
        avg_rating = sum(ratings) / len(ratings)
        if avg_rating >= 4.5:
            highly_rated_books.append({
                'title': children_books[purchase_id],
                'average_rating': round(avg_rating, 2),
                'review_count': len(ratings)
            })

# Sort by average rating descending, then by review count descending
highly_rated_books.sort(key=lambda x: (x['average_rating'], x['review_count']), reverse=True)

# Summary statistics
total_children_books = len(children_books)
books_with_reviews = len(book_ratings)
books_highly_rated = len(highly_rated_books)

print(f"Summary:")
